// 配信設定を環境変数から取得
// LINE_BROADCAST_MESSAGE: 送信するメッセージ本文
// LINE_BROADCAST_MODE: 'broadcast' (全体) or 'multicast' (指定ユーザー)
// LINE_BROADCAST_USE_SHEET: 'true' にするとGoogleスプレッドシートからユーザーID取得

const message = process.env.LINE_BROADCAST_MESSAGE 
  || '本日のお知らせです。\nいつもご利用ありがとうございます。';
const mode = process.env.LINE_BROADCAST_MODE || 'broadcast';
const useSheet = process.env.LINE_BROADCAST_USE_SHEET === 'true';

return [{
  json: {
    message,
    mode,
    useSheet
  }
}];

// スプレッドシートから取得したユーザーIDリストを整形
// スプレッドシートのカラム名は 'userId' または 'user_id' を想定
const rows = $input.all();
const userIdColumn = process.env.LINE_SHEET_USERID_COLUMN || 'userId';

const userIds = rows
  .map(r => r.json[userIdColumn] || r.json['user_id'] || r.json['UserId'])
  .filter(id => typeof id === 'string' && id.startsWith('U') && id.length === 33);

if (userIds.length === 0) {
  throw new Error('スプレッドシートから有効なユーザーIDが取得できませんでした。カラム名を確認してください。');
}

return [{
  json: {
    userIds,
    message: $input.first().json.message || process.env.LINE_BROADCAST_MESSAGE || '本日のお知らせです。',
    mode: 'multicast'
  }
}];

// Broadcastモード（全体配信）の場合はユーザーIDリスト不要
const message = $input.first().json.message;
return [{
  json: {
    message,
    mode: 'broadcast',
    userIds: null
  }
}];

// 送信方式に応じてAPIエンドポイントとボディを構築
const item = $input.first().json;
const mode = item.mode || 'broadcast';
const message = item.message;
const userIds = item.userIds;

let endpoint;
let body;

if (mode === 'multicast' && userIds && userIds.length > 0) {
  endpoint = 'https://api.line.me/v2/bot/message/multicast';
  body = {
    to: userIds,
    messages: [{ type: 'text', text: message }]
  };
} else {
  endpoint = 'https://api.line.me/v2/bot/message/broadcast';
  body = {
    messages: [{ type: 'text', text: message }]
  };
}

return [{
  json: {
    endpoint,
    body: JSON.stringify(body),
    mode,
    recipientCount: userIds ? userIds.length : 'all'
  }
}];

// 送信結果のログ出力
const result = $input.first().json;
console.log('[WF-C] 一斉送信完了:', JSON.stringify(result));
return [{ json: { status: 'completed', result } }];
